<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function lrepError(m){$('.isi_warning_delete').text(m||'Leave Report gagal diproses.');$('.error_data_delete').fadeIn();}
function lrepFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),employee_id:$('#filter_employee_id').val(),department_code:$('#filter_department_code').val(),job_title_id:$('#filter_job_title_id').val(),leave_type:$('#filter_leave_type').val(),workflow_status:$('#filter_workflow_status').val(),decision:$('#filter_decision').val(),approval_level:$('#filter_approval_level').val(),impact_type:$('#filter_impact_type').val(),keyword:$('#filter_keyword').val()};}
function ajaxSel(s,act,ph){$(s).select2({width:'100%',allowClear:true,placeholder:ph,ajax:{url:'<?=base_admin();?>modul/leave_report/leave_report_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.lrep-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_leave_type,#filter_workflow_status,#filter_decision,#filter_approval_level,#filter_impact_type').select2({width:'100%',allowClear:true});ajaxSel('#filter_employee_id','employee_search','Semua Employee');ajaxSel('#filter_department_code','department_search','Semua Department');ajaxSel('#filter_job_title_id','job_title_search','Semua Job Title');}
var dt=$('#dtb_leave_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'72px',targets:1}],ajax:{url:'<?=base_admin();?>modul/leave_report/leave_report_data.php',type:'post',data:function(d){$.extend(d,lrepFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_pending').text(k.pending||0);$('#kpi_approved').text(k.approved||0);$('#kpi_exception').text(k.exception||0);$('#kpi_requested_days').text(k.requested_days||0);$('#kpi_quota').text(k.quota_deducted||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);lrepError('Data Leave Report gagal dimuat.');}}});
$('#btn_filter_lrep').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_lrep').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_employee_id,#filter_department_code,#filter_job_title_id,#filter_leave_type,#filter_workflow_status,#filter_decision,#filter_approval_level,#filter_impact_type').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_lrep').click(function(){window.location='<?=base_admin();?>modul/leave_report/leave_report_action.php?act=export&'+$.param(lrepFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$(document).on('click','.btn-lrep-detail',function(){$.post('<?=base_admin();?>modul/leave_report/leave_report_action.php?act=detail',{id:$(this).data('id')},function(h){$('#lrep_detail_body').html(h);$('#modal_lrep_detail').modal('show');});});
});
</script>
